module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const heads = String(args.labels || 'Strengths,Weaknesses,Opportunities,Threats').split(',').map((x) => x.trim());
const cells = sections.slice(0, 4).map((s) => (s || '').trim());
while (cells.length < 4) cells.push('');
const keys = ['s', 'w', 'o', 't'];
let html = `\n\n<div class="mdp-mod-swot">`;
cells.forEach((c, i) => {
  html += `<div class="mdp-swot-cell mdp-swot-${keys[i]}"><div class="mdp-swot-head">${esc(heads[i] || '')}</div><div class="mdp-swot-body">\n\n${c}\n\n</div></div>`;
});
html += `</div>\n\n`;
return html;
